package com.example.demo.ui;
import com.example.demo.services.ReporteService;import com.vaadin.flow.component.html.*;import com.vaadin.flow.component.orderedlayout.VerticalLayout;import com.vaadin.flow.router.*;import com.vaadin.flow.server.StreamResource;import java.io.ByteArrayInputStream;import java.nio.charset.StandardCharsets;import java.text.NumberFormat;import java.util.*;
@Route(value="reportes",layout=MainLayout.class)@PageTitle("Reportes | Franco")public class ReportesView extends VerticalLayout{
private static final NumberFormat MONEY=NumberFormat.getCurrencyInstance(Locale.of("es","AR"));private static final String[]COLORS={"#2563EB","#16A34A","#F59E0B","#DC2626","#7C3AED"};
public ReportesView(ReporteService service){addClassName("content-view");setSizeFull();var r=service.resumen();Anchor export=new Anchor(new StreamResource("ventas.csv",()->new ByteArrayInputStream(service.exportarVentasCsv().getBytes(StandardCharsets.UTF_8))),"Exportar ventas CSV");export.getElement().setAttribute("download",true);Paragraph summary=new Paragraph(r.cantidadVentas()+" ventas confirmadas · "+MONEY.format(r.ingresosTotales())+" facturados · "+MONEY.format(r.gananciaEstimada())+" de ganancia estimada · "+r.stockBajo()+" productos con stock bajo");summary.addClassName("report-summary");Div charts=new Div();charts.addClassName("report-grid");charts.add(barChart("Productos más vendidos",r.masVendidos().stream().map(x->new Point(x.producto(),x.cantidad(),x.cantidad().stripTrailingZeros().toPlainString()+" "+x.unidad())).toList()),barChart("Ventas por día de la semana",r.ventasPorDia().stream().map(x->new Point(capitalize(x.etiqueta()),x.valor(),x.valor().toPlainString()+" ventas")).toList()),barChart("Horarios con más ventas",r.ventasPorHora().stream().map(x->new Point(x.etiqueta(),x.valor(),x.valor().toPlainString()+" ventas")).toList()),donut("Medios de pago",r.mediosPago()));add(ViewSupport.header("Reportes",export),summary,charts);}
private Div barChart(String title,List<Point>points){Div chart=section(title);java.math.BigDecimal max=points.stream().map(Point::value).max(java.math.BigDecimal::compareTo).orElse(java.math.BigDecimal.ONE);for(Point point:points){Div label=new Div(new Span(point.label()),new Span(point.text()));label.addClassName("bar-label");Div fill=new Div();fill.addClassName("bar-fill");double width=max.signum()==0?0:point.value().doubleValue()/max.doubleValue()*100;fill.getStyle().set("width",String.format(Locale.US,"%.2f%%",width));Div track=new Div(fill);track.addClassName("bar-track");Div row=new Div(label,track);row.addClassName("bar-row");chart.add(row);}return chart;}
private Div donut(String title,List<ReporteService.Metrica>points){Div chart=section(title);double total=points.stream().mapToDouble(x->x.valor().doubleValue()).sum(),cursor=0;StringBuilder gradient=new StringBuilder("conic-gradient(");Div legend=new Div();legend.addClassName("chart-legend");for(int i=0;i<points.size();i++){double end=total==0?cursor:cursor+points.get(i).valor().doubleValue()/total*100;if(i>0)gradient.append(',');gradient.append(COLORS[i%COLORS.length]).append(' ').append(cursor).append("% ").append(end).append('%');Span item=new Span(points.get(i).etiqueta()+" · "+points.get(i).valor().toPlainString());item.getStyle().set("--legend-color",COLORS[i%COLORS.length]);item.addClassName("legend-item");legend.add(item);cursor=end;}gradient.append(')');Div ring=new Div(new Span(String.valueOf(points.stream().mapToLong(x->x.valor().longValue()).sum())));ring.addClassName("donut-chart");ring.getStyle().set("background",gradient.toString());Div content=new Div(ring,legend);content.addClassName("donut-content");chart.add(content);return chart;}
private Div section(String title){Div result=new Div(new H3(title));result.addClassName("chart-panel");return result;}private String capitalize(String value){return value.isEmpty()?value:Character.toUpperCase(value.charAt(0))+value.substring(1);}private record Point(String label,java.math.BigDecimal value,String text){}}
